8109 /// Match clamp pattern for float types without care about NaNs or signed zeros.
8110 /// Given non-min/max outer cmp/select from the clamp pattern this
8111 /// function recognizes if it can be substitued by a "canonical" min/max
8112 /// pattern.
8113 static SelectPatternResult matchFastFloatClamp(CmpInst::Predicate Pred,
8114                                                Value *CmpLHS, Value *CmpRHS,
8115                                                Value *TrueVal, Value *FalseVal,
8116                                                Value *&LHS, Value *&RHS) {
