8118   //   X < C1 ? C1 : Min(X, C2) --> Max(C1, Min(X, C2))
8119   //   X > C1 ? C1 : Max(X, C2) --> Min(C1, Max(X, C2))
8120   // and return description of the outer Max/Min.
8121 
8122   // First, check if select has inverse order:
8123   if (CmpRHS == FalseVal) {
8124     std::swap(TrueVal, FalseVal);
8125     Pred = CmpInst::getInversePredicate(Pred);
8126   }
8127 
8128   // Assume success now. If there's no match, callers should not use these anyway.
8129   LHS = TrueVal;
8130   RHS = FalseVal;
8131 
8132   const APFloat *FC1;
8133   if (CmpRHS != TrueVal || !match(CmpRHS, m_APFloat(FC1)) || !FC1->isFinite())
8134     return {SPF_UNKNOWN, SPNB_NA, false};
8135 
8136   const APFloat *FC2;
8137   switch (Pred) {
8138   case CmpInst::FCMP_OLT:
8139   case CmpInst::FCMP_OLE:
8140   case CmpInst::FCMP_ULT:
8141   case CmpInst::FCMP_ULE:
8142     if (match(FalseVal,
8143               m_CombineOr(m_OrdFMin(m_Specific(CmpLHS), m_APFloat(FC2)),
8144                           m_UnordFMin(m_Specific(CmpLHS), m_APFloat(FC2)))) &&
8145         *FC1 < *FC2)
8146       return {SPF_FMAXNUM, SPNB_RETURNS_ANY, false};
8147     break;
8148   case CmpInst::FCMP_OGT:
8149   case CmpInst::FCMP_OGE:
8150   case CmpInst::FCMP_UGT:
8151   case CmpInst::FCMP_UGE:
8152     if (match(FalseVal,
8153               m_CombineOr(m_OrdFMax(m_Specific(CmpLHS), m_APFloat(FC2)),
8154                           m_UnordFMax(m_Specific(CmpLHS), m_APFloat(FC2)))) &&
8155         *FC1 > *FC2)
8156       return {SPF_FMINNUM, SPNB_RETURNS_ANY, false};
8157     break;
8158   default:
