8165 /// Recognize variations of:
8166 ///   CLAMP(v,l,h) ==> ((v) < (l) ? (l) : ((v) > (h) ? (h) : (v)))
8167 static SelectPatternResult matchClamp(CmpInst::Predicate Pred,
8168                                       Value *CmpLHS, Value *CmpRHS,
8169                                       Value *TrueVal, Value *FalseVal) {
8170   // Swap the select operands and predicate to match the patterns below.
8171   if (CmpRHS != TrueVal) {
8172     Pred = ICmpInst::getSwappedPredicate(Pred);
8173     std::swap(TrueVal, FalseVal);
8174   }
8175   const APInt *C1;
8176   if (CmpRHS == TrueVal && match(CmpRHS, m_APInt(C1))) {
8177     const APInt *C2;
8178     // (X <s C1) ? C1 : SMIN(X, C2) ==> SMAX(SMIN(X, C2), C1)
8179     if (match(FalseVal, m_SMin(m_Specific(CmpLHS), m_APInt(C2))) &&
8180         C1->slt(*C2) && Pred == CmpInst::ICMP_SLT)
8181       return {SPF_SMAX, SPNB_NA, false};
8182 
8183     // (X >s C1) ? C1 : SMAX(X, C2) ==> SMIN(SMAX(X, C2), C1)
8184     if (match(FalseVal, m_SMax(m_Specific(CmpLHS), m_APInt(C2))) &&
8185         C1->sgt(*C2) && Pred == CmpInst::ICMP_SGT)
8186       return {SPF_SMIN, SPNB_NA, false};
8187 
8188     // (X <u C1) ? C1 : UMIN(X, C2) ==> UMAX(UMIN(X, C2), C1)
8189     if (match(FalseVal, m_UMin(m_Specific(CmpLHS), m_APInt(C2))) &&
8190         C1->ult(*C2) && Pred == CmpInst::ICMP_ULT)
8191       return {SPF_UMAX, SPNB_NA, false};
8192 
8193     // (X >u C1) ? C1 : UMAX(X, C2) ==> UMIN(UMAX(X, C2), C1)
8194     if (match(FalseVal, m_UMax(m_Specific(CmpLHS), m_APInt(C2))) &&
8195         C1->ugt(*C2) && Pred == CmpInst::ICMP_UGT)
8196       return {SPF_UMIN, SPNB_NA, false};
